const raw = $input.first().json;
const outputText = (raw.output ?? JSON.stringify(raw)).trim();

// Parse — strip markdown fences if present
let parsed;
try {
  const clean = outputText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '');
  parsed = JSON.parse(clean);
  if (Array.isArray(parsed)) parsed = parsed[0] ?? parsed;
} catch {
  return [{ json: { output: outputText, parse_error: true } }];
}

// key_terms[] from agent → fields{} expected by frontend
// Playbook key_term_name maps label to snake_case key
const LABEL_TO_KEY = {
  'Commencement Date': 'commencement_date',
  'Expiry Date': 'expiry_date',
  'Annual Payment': 'annual_payment',
  'Discount Rate (IBR)': 'discount_rate',
  'Escalation Rate': 'escalation_rate',
  'Renewal Options': 'renewal_options',
  'Termination Rights': 'termination_rights',
  'Security Deposit': 'security_deposit',
  'ROU Asset Scope': 'rou_asset_scope',
  'Governing Law': 'governing_law',
};

const RISK_WEIGHTS = {
  commencement_date: 10, expiry_date: 10, annual_payment: 10, discount_rate: 10,
  renewal_options: 8, termination_rights: 8, escalation_rate: 7,
  rou_asset_scope: 6, security_deposit: 5, governing_law: 3,
};

const fields = {};
for (const item of (parsed.key_terms ?? [])) {
  const key = LABEL_TO_KEY[item.label] ?? item.label.toLowerCase().replace(/\s+/g, '_');
  const missing = !item.value || item.value === 'Not specified';
  fields[key] = {
    value: missing ? null : item.value,
    confidence: missing ? 0 : (item.confidence ?? 0.85),
    source_clause: item.source_clause ?? null,
  };
}

const isMissing = (f) => !f || f.value === null || f.value === undefined;
const terms_found = Object.keys(fields).filter(k => !isMissing(fields[k]));
const terms_missing = Object.keys(fields).filter(k => isMissing(fields[k]));

// Risk score: deduct weight for each missing field
const totalWeight = Object.keys(RISK_WEIGHTS).reduce((s, k) => s + RISK_WEIGHTS[k], 0);
const missingWeight = terms_missing.reduce((s, k) => s + (RISK_WEIGHTS[k] ?? 0), 0);
const risk_score = Math.round(100 * (1 - missingWeight / totalWeight));

// Risk flags for missing fields — severity from risk_weight
const risk_flags = terms_missing.map(key => {
  const w = RISK_WEIGHTS[key] ?? 0;
  const severity = w >= 8 ? 'high' : w >= 5 ? 'medium' : 'low';
  return {
    id: `missing_${key}`,
    severity,
    title: `${key.replace(/_/g, ' ')} not found`,
    description: severity === 'high'
      ? `Required for IFRS 16 compliance — resolve before exporting the report.`
      : `Verify manually and update if applicable.`,
    field: key,
  };
});

return [{
  json: {
    contract_type: parsed.contract_type ?? 'LEASE',
    terms_found,
    terms_missing,
    risk_score,
    analyzed_at: new Date().toISOString(),
    key_terms: parsed.key_terms ?? [],
    fields,
    risk_flags,
  }
}];
